async (params, browser) => {
  // Open Internet Archive search
  await browser.open(`https://archive.org/search?query=${params.query}`)

  // Wait for page
  await browser.waitForSelector('.results, .item-ia, .SRPs, [class*="search-results"], .content', 15000)

  // Let page render
  await browser.wait(2500)

  // Extract data
  const result = await browser.evaluate(`const items = []; document.querySelectorAll('.item-ia, .result-item, [data-id], [class*="search-tile"], .SRPItem, article').forEach((el, i) => { if (i < 15) { const titleEl = el.querySelector('.ttl, .title a, a[href*="/details/"], .item-title, h4 a'); const typeEl = el.querySelector('.type, .mediatype, .item-mediatype'); const descEl = el.querySelector('.description, .item-description, p'); items.push({ title: titleEl?.textContent?.trim() || '', url: titleEl?.href || '', type: typeEl?.textContent?.trim() || '', description: descEl?.textContent?.trim()?.slice(0, 200) || '' }); } }); return { query: '' + params.query + '', item_count: items.length, items };`)

  return result
}
